  1‚Üípackage handlers
  2‚Üí
  3‚Üíimport (
  4‚Üí	"encoding/json"
  5‚Üí	"entire-dashboard/db"
  6‚Üí	gitreader "entire-dashboard/git"
  7‚Üí	"log"
  8‚Üí	"net/http"
  9‚Üí	"path/filepath"
 10‚Üí	"strconv"
 11‚Üí)
 12‚Üí
 13‚Üítype Handler struct {
 14‚Üí	store *db.Store
 15‚Üí}
 16‚Üí
 17‚Üífunc New(store *db.Store) *Handler {
 18‚Üí	return &Handler{store: store}
 19‚Üí}
 20‚Üí
 21‚Üífunc (h *Handler) GetRepos(w http.ResponseWriter, r *http.Request) {
 22‚Üí	repos, err := h.store.GetRepos()
 23‚Üí	if err != nil {
 24‚Üí		http.Error(w, err.Error(), http.StatusInternalServerError)
 25‚Üí		return
 26‚Üí	}
 27‚Üí	writeJSON(w, repos)
 28‚Üí}
 29‚Üí
 30‚Üífunc (h *Handler) AddRepo(w http.ResponseWriter, r *http.Request) {
 31‚Üí	var req struct {
 32‚Üí		Path string `json:"path"`
 33‚Üí	}
 34‚Üí	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
 35‚Üí		http.Error(w, "invalid request body", http.StatusBadRequest)
 36‚Üí		return
 37‚Üí	}
 38‚Üí	if req.Path == "" {
 39‚Üí		http.Error(w, "path is required", http.StatusBadRequest)
 40‚Üí		return
 41‚Üí	}
 42‚Üí
 43‚Üí	absPath, err := filepath.Abs(req.Path)
 44‚Üí	if err != nil {
 45‚Üí		http.Error(w, "invalid path: "+err.Error(), http.StatusBadRequest)
 46‚Üí		return
 47‚Üí	}
 48‚Üí
 49‚Üí	name := filepath.Base(absPath)
 50‚Üí	repo, err := h.store.AddRepo(absPath, name)
 51‚Üí	if err != nil {
 52‚Üí		http.Error(w, "failed to add repo: "+err.Error(), http.StatusInternalServerError)
 53‚Üí		return
 54‚Üí	}
 55‚Üí	writeJSON(w, repo)
 56‚Üí}
