 58‚Üífunc (h *Handler) DeleteRepo(w http.ResponseWriter, r *http.Request) {
 59‚Üí	idStr := r.PathValue("id")
 60‚Üí	id, err := strconv.Atoi(idStr)
 61‚Üí	if err != nil {
 62‚Üí		http.Error(w, "invalid id", http.StatusBadRequest)
 63‚Üí		return
 64‚Üí	}
 65‚Üí	if err := h.store.DeleteRepo(id); err != nil {
 66‚Üí		http.Error(w, "failed to delete repo: "+err.Error(), http.StatusInternalServerError)
