 72‚Üífunc (h *Handler) GetDailyStats(w http.ResponseWriter, r *http.Request) {
 73‚Üí	repoPath := r.URL.Query().Get("repo")
 74‚Üí	stats, err := h.store.GetDailyStats(repoPath)
 75‚Üí	if err != nil {
 76‚Üí		http.Error(w, err.Error(), http.StatusInternalServerError)
 77‚Üí		return
 78‚Üí	}
