 81‚Üí
 82‚Üífunc (h *Handler) GetSessions(w http.ResponseWriter, r *http.Request) {
 83‚Üí	repoPath := r.URL.Query().Get("repo")
 84‚Üí	sessions, err := h.store.GetSessions(repoPath)
 85‚Üí	if err != nil {
 86‚Üí		http.Error(w, err.Error(), http.StatusInternalServerError)
 87‚Üí		return
 88‚Üí	}
 89‚Üí	writeJSON(w, sessions)
 90‚Üí}
 91‚Üí
 92‚Üí// Sync reads from the git shadow branch and upserts into SQLite.
 93‚Üí// If ?repo= is specified, syncs that repo only. Otherwise syncs all registered repos.
 94‚Üífunc (h *Handler) Sync(w http.ResponseWriter, r *http.Request) {
 95‚Üí	repoPath := r.URL.Query().Get("repo")
 96‚Üí
 97‚Üí	var repos []string
 98‚Üí	if repoPath != "" {
 99‚Üí		repos = append(repos, repoPath)
100‚Üí	} else {
101‚Üí		repoList, err := h.store.GetRepos()
102‚Üí		if err != nil {
103‚Üí			http.Error(w, "failed to list repos: "+err.Error(), http.StatusInternalServerError)
104‚Üí			return
105‚Üí		}
106‚Üí		for _, r := range repoList {
107‚Üí			repos = append(repos, r.Path)
108‚Üí		}
109‚Üí	}
110‚Üí
111‚Üí	totalFound := 0
112‚Üí	totalInserted := 0
113‚Üí
114‚Üí	for _, rp := range repos {
115‚Üí		reader := gitreader.NewReader(rp)
116‚Üí		sessions, err := reader.ReadAllSessions()
117‚Üí		if err != nil {
118‚Üí			log.Printf("sync error for %s: %v", rp, err)
119‚Üí			continue
120‚Üí		}
121‚Üí
122‚Üí		inserted := 0
123‚Üí		for _, sess := range sessions {
124‚Üí			sess.RepoPath = rp
125‚Üí			if sess.SessionID == "" {
126‚Üí				log.Printf("skip session with empty session_id in %s", rp)
127‚Üí				continue
128‚Üí			}
129‚Üí			exists, err := h.store.SessionExists(sess.SessionID)
130‚Üí			if err != nil {
131‚Üí				log.Printf("check exists error: %v", err)
132‚Üí				continue
133‚Üí			}
134‚Üí			if exists {
135‚Üí				continue
136‚Üí			}
137‚Üí			if err := h.store.UpsertSession(sess); err != nil {
138‚Üí				log.Printf("upsert error: %v", err)
139‚Üí				continue
140‚Üí			}
141‚Üí			inserted++
142‚Üí		}
143‚Üí		totalFound += len(sessions)
144‚Üí		totalInserted += inserted
145‚Üí	}
146‚Üí
147‚Üí	writeJSON(w, map[string]any{
148‚Üí		"total_found": totalFound,
149‚Üí		"inserted":    totalInserted,
150‚Üí		"message":     "sync complete",
151‚Üí	})
152‚Üí}
153‚Üí
154‚Üífunc writeJSON(w http.ResponseWriter, v any) {
155‚Üí	w.Header().Set("Content-Type", "application/json")
156‚Üí	json.NewEncoder(w).Encode(v)
157‚Üí}
