  1‚Üípackage git
  2‚Üí
  3‚Üíimport (
  4‚Üí	"encoding/json"
  5‚Üí	"entire-dashboard/models"
  6‚Üí	"fmt"
  7‚Üí	"os/exec"
  8‚Üí	"strconv"
  9‚Üí	"strings"
 10‚Üí)
 11‚Üí
 12‚Üíconst shadowBranch = "entire/checkpoints/v1"
 13‚Üí
 14‚Üí// Reader reads Entire checkpoint data from a git repository's shadow branch.
 15‚Üítype Reader struct {
 16‚Üí	repoPath string
 17‚Üí}
 18‚Üí
 19‚Üífunc NewReader(repoPath string) *Reader {
 20‚Üí	return &Reader{repoPath: repoPath}
 21‚Üí}
 22‚Üí
 23‚Üí// ReadAllSessions extracts all session metadata from the shadow branch.
 24‚Üífunc (r *Reader) ReadAllSessions() ([]models.Session, error) {
 25‚Üí	// List top-level directories (2-char prefixes)
 26‚Üí	prefixes, err := r.lsTree(shadowBranch)
 27‚Üí	if err != nil {
 28‚Üí		return nil, fmt.Errorf("list prefixes: %w", err)
 29‚Üí	}
 30‚Üí
 31‚Üí	var sessions []models.Session
 32‚Üí	for _, prefix := range prefixes {
 33‚Üí		// List checkpoint IDs under each prefix
 34‚Üí		checkpointIDs, err := r.lsTree(shadowBranch + ":" + prefix + "/")
 35‚Üí		if err != nil {
 36‚Üí			continue
 37‚Üí		}
 38‚Üí		for _, cpID := range checkpointIDs {
 39‚Üí			path := prefix + "/" + cpID
 40‚Üí			ss, err := r.readCheckpointSessions(path, prefix+cpID)
 41‚Üí			if err != nil {
 42‚Üí				continue
 43‚Üí			}
 44‚Üí			sessions = append(sessions, ss...)
 45‚Üí		}
 46‚Üí	}
 47‚Üí	return sessions, nil
 48‚Üí}
 49‚Üí
 50‚Üífunc (r *Reader) readCheckpointSessions(treePath, checkpointID string) ([]models.Session, error) {
 51‚Üí	// List entries in this checkpoint (numbered session dirs + metadata.json)
 52‚Üí	entries, err := r.lsTree(shadowBranch + ":" + treePath + "/")
 53‚Üí	if err != nil {
 54‚Üí		return nil, err
 55‚Üí	}
 56‚Üí
 57‚Üí	var sessions []models.Session
 58‚Üí	for _, entry := range entries {
 59‚Üí		// Only process numbered directories (session indices)
 60‚Üí		if _, err := strconv.Atoi(entry); err != nil {
 61‚Üí			continue
 62‚Üí		}
 63‚Üí
 64‚Üí		metaPath := treePath + "/" + entry + "/metadata.json"
 65‚Üí		meta, err := r.readSessionMeta(metaPath)
 66‚Üí		if err != nil {
 67‚Üí			continue
 68‚Üí		}
 69‚Üí
 70‚Üí		prompt := r.readFileContent(treePath + "/" + entry + "/prompt.txt")
 71‚Üí
 72‚Üí		sessions = append(sessions, models.Session{
 73‚Üí			CheckpointID:    meta.CheckpointID,
 74‚Üí			SessionID:       meta.SessionID,
 75‚Üí			Agent:           meta.Agent,
 76‚Üí			Branch:          meta.Branch,
 77‚Üí			CreatedAt:       meta.CreatedAt,
 78‚Üí			Prompt:          truncate(prompt, 500),
 79‚Üí			AgentLines:      meta.Attribution.AgentLines,
 80‚Üí			HumanAdded:      meta.Attribution.HumanAdded,
 81‚Üí			HumanModified:   meta.Attribution.HumanModified,
 82‚Üí			HumanRemoved:    meta.Attribution.HumanRemoved,
 83‚Üí			TotalCommitted:  meta.Attribution.TotalCommitted,
 84‚Üí			AgentPercentage: meta.Attribution.AgentPercentage,
 85‚Üí			InputTokens:     meta.TokenUsage.InputTokens,
 86‚Üí			OutputTokens:    meta.TokenUsage.OutputTokens,
 87‚Üí			APICallCount:    meta.TokenUsage.APICallCount,
 88‚Üí		})
 89‚Üí	}
 90‚Üí	return sessions, nil
 91‚Üí}
 92‚Üí
 93‚Üífunc (r *Reader) readSessionMeta(path string) (models.SessionMeta, error) {
 94‚Üí	var meta models.SessionMeta
 95‚Üí	content := r.readFileContent(path)
 96‚Üí	if content == "" {
 97‚Üí		return meta, fmt.Errorf("empty content at %s", path)
 98‚Üí	}
 99‚Üí	err := json.Unmarshal([]byte(content), &meta)
100‚Üí	return meta, err
101‚Üí}
102‚Üí
103‚Üífunc (r *Reader) readFileContent(path string) string {
104‚Üí	out, err := r.gitShow(shadowBranch + ":" + path)
105‚Üí	if err != nil {
106‚Üí		return ""
107‚Üí	}
108‚Üí	return out
109‚Üí}
110‚Üí
111‚Üífunc (r *Reader) lsTree(ref string) ([]string, error) {
112‚Üí	out, err := exec.Command("git", "-C", r.repoPath, "ls-tree", "--name-only", ref).Output()
113‚Üí	if err != nil {
114‚Üí		return nil, err
115‚Üí	}
116‚Üí	lines := strings.Split(strings.TrimSpace(string(out)), "\n")
117‚Üí	var result []string
118‚Üí	for _, l := range lines {
119‚Üí		l = strings.TrimSpace(l)
120‚Üí		if l != "" {
121‚Üí			result = append(result, l)
122‚Üí		}
123‚Üí	}
124‚Üí	return result, nil
125‚Üí}
126‚Üí
127‚Üífunc (r *Reader) gitShow(ref string) (string, error) {
128‚Üí	out, err := exec.Command("git", "-C", r.repoPath, "show", ref).Output()
129‚Üí	if err != nil {
130‚Üí		return "", err
131‚Üí	}
132‚Üí	return string(out), nil
133‚Üí}
134‚Üí
135‚Üífunc truncate(s string, maxLen int) string {
136‚Üí	runes := []rune(s)
137‚Üí	if len(runes) <= maxLen {
138‚Üí		return s
139‚Üí	}
140‚Üí	return string(runes[:maxLen]) + "..."
141‚Üí}
