  1‚Üíimport { useEffect, useState, useCallback } from "react";
  2‚Üíimport { DailyDashboard } from "./components/DailyDashboard";
  3‚Üíimport { SessionTimeline } from "./components/SessionTimeline";
  4‚Üíimport {
  5‚Üí  fetchDailyStats,
  6‚Üí  fetchSessions,
  7‚Üí  fetchRepos,
  8‚Üí  addRepo,
  9‚Üí  deleteRepo,
 10‚Üí  syncData,
 11‚Üí} from "./api";
 12‚Üíimport type { DailyStat, Repository, Session } from "./types";
 13‚Üíimport "./App.css";
 14‚Üí
 15‚Üífunction App() {
 16‚Üí  const [repos, setRepos] = useState<Repository[]>([]);
 17‚Üí  const [selectedRepo, setSelectedRepo] = useState<string>("");
 18‚Üí  const [dailyStats, setDailyStats] = useState<DailyStat[]>([]);
 19‚Üí  const [sessions, setSessions] = useState<Session[]>([]);
 20‚Üí  const [syncing, setSyncing] = useState(false);
 21‚Üí  const [lastSynced, setLastSynced] = useState<string>("");
 22‚Üí  const [newRepoPath, setNewRepoPath] = useState("");
 23‚Üí  const [addingRepo, setAddingRepo] = useState(false);
 24‚Üí  const [showRepoForm, setShowRepoForm] = useState(false);
 25‚Üí  const [loadError, setLoadError] = useState<string>("");
 26‚Üí
 27‚Üí  const loadRepos = useCallback(async () => {
 28‚Üí    try {
 29‚Üí      const r = await fetchRepos();
 30‚Üí      setRepos(r);
 31‚Üí    } catch (e) {
 32‚Üí      setRepos([]);
 33‚Üí      setLoadError(e instanceof Error ? e.message : "„É™„ÉĚ„āł„Éą„É™ŚŹĖŚĺó„ĀęŚ§Īśēó„Āó„Āĺ„Āó„Āü");
 34‚Üí    }
 35‚Üí  }, []);
 36‚Üí
 37‚Üí  const loadData = useCallback(async () => {
 38‚Üí    try {
 39‚Üí      setLoadError("");
 40‚Üí      const repoFilter = selectedRepo || undefined;
 41‚Üí      const [stats, sess] = await Promise.all([
 42‚Üí        fetchDailyStats(repoFilter),
 43‚Üí        fetchSessions(repoFilter),
 44‚Üí      ]);
 45‚Üí      setDailyStats(stats);
 46‚Üí      setSessions(sess);
 47‚Üí    } catch (e) {
 48‚Üí      setDailyStats([]);
 49‚Üí      setSessions([]);
 50‚Üí      setLoadError(e instanceof Error ? e.message : "„Éá„Éľ„āŅŚŹĖŚĺó„ĀęŚ§Īśēó„Āó„Āĺ„Āó„Āü");
 51‚Üí    }
 52‚Üí  }, [selectedRepo]);
 53‚Üí
 54‚Üí  useEffect(() => {
 55‚Üí    loadRepos();
 56‚Üí  }, [loadRepos]);
 57‚Üí
 58‚Üí  useEffect(() => {
 59‚Üí    loadData();
 60‚Üí  }, [loadData]);
 61‚Üí
 62‚Üí  const handleSync = async () => {
 63‚Üí    setSyncing(true);
 64‚Üí    try {
 65‚Üí      const repoFilter = selectedRepo || undefined;
 66‚Üí      await syncData(repoFilter);
 67‚Üí      setLastSynced(new Date().toLocaleString("ja-JP"));
 68‚Üí      await loadData();
 69‚Üí    } catch {
 70‚Üí      setLastSynced("Sync failed");
 71‚Üí    } finally {
 72‚Üí      setSyncing(false);
 73‚Üí    }
 74‚Üí  };
 75‚Üí
 76‚Üí  const handleAddRepo = async () => {
 77‚Üí    if (addingRepo || !newRepoPath.trim()) return;
 78‚Üí    setAddingRepo(true);
 79‚Üí    try {
 80‚Üí      await addRepo(newRepoPath.trim());
 81‚Üí      setNewRepoPath("");
 82‚Üí      setShowRepoForm(false);
 83‚Üí      await loadRepos();
 84‚Üí    } catch (e) {
 85‚Üí      alert(`Failed to add repo: ${e instanceof Error ? e.message : e}`);
 86‚Üí    } finally {
 87‚Üí      setAddingRepo(false);
 88‚Üí    }
 89‚Üí  };
 90‚Üí
 91‚Üí  const handleDeleteRepo = async (id: number) => {
 92‚Üí    try {
 93‚Üí      const target = repos.find((r) => r.id === id);
 94‚Üí      await deleteRepo(id);
 95‚Üí      await loadRepos();
 96‚Üí      if (target?.path === selectedRepo) {
 97‚Üí        setSelectedRepo("");
 98‚Üí      }
 99‚Üí    } catch (e) {
100‚Üí      alert(`Failed to delete repo: ${e instanceof Error ? e.message : e}`);
101‚Üí    }
102‚Üí  };
103‚Üí
104‚Üí  // Compute KPIs
105‚Üí  const totalAgent = dailyStats.reduce((sum, d) => sum + d.agent_lines, 0);
106‚Üí  const totalHuman = dailyStats.reduce((sum, d) => sum + d.human_lines, 0);
107‚Üí  const totalAll = totalAgent + totalHuman;
108‚Üí  const overallPct =
109‚Üí    totalAll > 0 ? ((totalAgent / totalAll) * 100).toFixed(1) : "0.0";
110‚Üí  const totalSessions = sessions.length;
111‚Üí
112‚Üí  return (
113‚Üí    <div className="dashboard">
114‚Üí      <header className="header">
115‚Üí        <h1 className="header-title">Entire Dashboard</h1>
116‚Üí        <div className="header-actions">
117‚Üí          {lastSynced && (
118‚Üí            <span className="sync-status">Last synced: {lastSynced}</span>
119‚Üí          )}
120‚Üí          <button
121‚Üí            onClick={handleSync}
122‚Üí            disabled={syncing}
123‚Üí            className="sync-button"
124‚Üí          >
125‚Üí            {syncing ? "Syncing..." : "Sync"}
126‚Üí          </button>
127‚Üí        </div>
128‚Üí      </header>
129‚Üí
130‚Üí      {/* Repository Selector */}
131‚Üí      <div className="repo-bar">
132‚Üí        <div className="repo-selector">
133‚Üí          <select
134‚Üí            value={selectedRepo}
135‚Üí            onChange={(e) => setSelectedRepo(e.target.value)}
136‚Üí            className="repo-select"
137‚Üí          >
138‚Üí            <option value="">All Repositories</option>
139‚Üí            {repos.map((r) => (
140‚Üí              <option key={r.id} value={r.path}>
141‚Üí                {r.name} ({r.path})
142‚Üí              </option>
143‚Üí            ))}
144‚Üí          </select>
145‚Üí
146‚Üí          <button
147‚Üí            className="repo-add-button"
148‚Üí            onClick={() => setShowRepoForm(!showRepoForm)}
149‚Üí          >
150‚Üí            + Add
151‚Üí          </button>
152‚Üí        </div>
153‚Üí
154‚Üí        {showRepoForm && (
155‚Üí          <div className="repo-form">
156‚Üí            <input
157‚Üí              type="text"
158‚Üí              value={newRepoPath}
159‚Üí              onChange={(e) => setNewRepoPath(e.target.value)}
160‚Üí              onKeyDown={(e) => e.key === "Enter" && handleAddRepo()}
161‚Üí              placeholder="/path/to/git/repository"
162‚Üí              className="repo-input"
163‚Üí              disabled={addingRepo}
164‚Üí            />
165‚Üí            <button
166‚Üí              onClick={handleAddRepo}
167‚Üí              disabled={addingRepo || !newRepoPath.trim()}
168‚Üí              className="sync-button"
169‚Üí            >
170‚Üí              {addingRepo ? "Adding..." : "Add"}
171‚Üí            </button>
172‚Üí          </div>
173‚Üí        )}
174‚Üí
175‚Üí        {repos.length > 0 && (
176‚Üí          <div className="repo-list">
177‚Üí            {repos.map((r) => (
178‚Üí              <div key={r.id} className="repo-tag">
179‚Üí                <span className="repo-tag-name">{r.name}</span>
180‚Üí                <span className="repo-tag-path">{r.path}</span>
181‚Üí                <button
