183‚Üí                  onClick={() => handleDeleteRepo(r.id)}
184‚Üí                  title="Remove repository"
185‚Üí                  aria-label={`${r.name} „āíŚČäťô§`}
186‚Üí                >
187‚Üí                  &times;
188‚Üí                </button>
189‚Üí              </div>
190‚Üí            ))}
191‚Üí          </div>
192‚Üí        )}
193‚Üí      </div>
194‚Üí
195‚Üí      {loadError && (
196‚Üí        <div style={{ color: "#d32f2f", background: "#fdecea", padding: "12px 16px", borderRadius: 8, marginBottom: 16, fontSize: 13 }}>
197‚Üí          {loadError}
